import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom';

function Login({ setToken }) {
  const [credentials, setCredentials] = useState({ username: 'admin', password: 'admin123' });
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('/admin/login', credentials);
      localStorage.setItem('adminToken', response.data.token);
      setToken(response.data.token);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Login failed');
    }
  };

  return (
    <div className="login-container">
      <div className="row justify-content-center">
        <div className="col-md-5 col-lg-4">
          <div className="login-card animate__animated animate__fadeInUp">
            <div className="text-center mb-4">
              <i className="bi bi-shield-check display-4 text-primary mb-3"></i>
              <h3 className="card-title mb-1">Vyntex Admin</h3>
              <p className="text-muted">Welcome back</p>
            </div>
            <form onSubmit={handleSubmit}>
              <div className="mb-4">
                <label className="form-label">Username</label>
                <input
                  type="text"
                  className="form-control form-control-lg"
                  placeholder="Enter username"
                  value={credentials.username}
                  onChange={(e) => setCredentials({...credentials, username: e.target.value})}
                  autoFocus
                />
              </div>
              <div className="mb-4">
                <label className="form-label">Password</label>
                <input
                  type="password"
                  className="form-control form-control-lg"
                  placeholder="Enter password"
                  value={credentials.password}
                  onChange={(e) => setCredentials({...credentials, password: e.target.value})}
                />
              </div>
              {error && <div className="alert alert-danger alert-dismissible fade show" role="alert">
                {error} <button type="button" className="btn-close" onClick={() => setError('')}></button>
              </div>}
              <button type="submit" className="btn btn-primary btn-lg w-100 py-3 mb-3" disabled={loading}>
                {loading ? <><i className="bi bi-hourglass-split me-2"></i>Loading...</> : 'Sign In'}
              </button>
            </form>
            <div className="text-center">
              <small className="text-muted">Default: <strong>admin / admin123</strong></small>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Login;
